def convert_units(value, from_unit, to_unit):
    supported = ['m', 'cm', 'mm', 'km']
    conversion_rates = {'m': 1, 'cm': 0.01, 'mm': 0.001, 'km': 1000}
    if from_unit not in supported or to_unit not in supported:
        raise ValueError('Unsupported unit type')
    if value < 0:
        raise ValueError('Cannot convert negative values')
    factor = conversion_rates[from_unit] / conversion_rates[to_unit]
    return value * factor

